=🔔 STALLED ONBOARDING ALERT 🔔
Customer: {{ $('HubSpot: Get Email').item.json.properties.firstname.value }}
Deal: {{ $('Code: Get Primary Contact').item.json.dealName }}
This customer has been in the 'Onboarding in Progress' stage for over 2 weeks. We just sent them an automated re-engagement email.  Please follow up with them.

parameters.jsCode:
// Get all deal items from the previous node.
const allDeals = $input.all();

// This list will hold our final, flat list of all contacts.
const allContactsList = [];

// Loop through each deal that was found.
for (const dealItem of allDeals) {

  // Get the list of associated contact IDs from this deal.
  const contactIds = dealItem.json.associations.associatedVids;

  // Get the deal's ID and name.
  const originalDealId = dealItem.json.dealId;
  const originalDealName = dealItem.json.properties.dealname.value;
  const dealLastContacted = dealItem.json.properties.notes_last_contacted ? dealItem.json.properties.notes_last_contacted.value : null;

  // Only proceed if the deal actually has contacts.
  if (contactIds && contactIds.length > 0) {

    // Limit to the first contact to avoid spamming multiple people.
    const primaryId = contactIds[0];

    allContactsList.push({
      json: {
        contactId: primaryId,
        dealId: originalDealId,
        dealName: originalDealName,
        dealLastContacted: dealLastContacted
      }
    });
  }
}

// Return the final list.
return allContactsList;
